Optimize this Go function that builds a large report string:

```go
func BuildReport(records []Record) string {
    result := ""
    for _, r := range records {
        result += fmt.Sprintf("ID: %d, Name: %s, Amount: $%.2f\n", r.ID, r.Name, r.Amount)
    }
    header := fmt.Sprintf("Report: %d records\n", len(records))
    result = header + result + fmt.Sprintf("Total: $%.2f\n", sumAmounts(records))
    return result
}
```

This function is called with 50,000+ records and takes over 2 seconds. Optimize it for performance.

Refactor this deeply nested Go function to be more readable:

```go
func ProcessOrder(ctx context.Context, order *Order, db *sql.DB) error {
    if order != nil {
        if order.Status == "pending" {
            if len(order.Items) > 0 {
                total := 0.0
                for _, item := range order.Items {
                    if item.Price > 0 {
                        if item.Quantity > 0 {
                            total += item.Price * float64(item.Quantity)
                        } else {
                            return fmt.Errorf("invalid quantity for item %s", item.Name)
                        }
                    } else {
                        return fmt.Errorf("invalid price for item %s", item.Name)
                    }
                }
                if total > 0 {
                    order.Total = total
                    order.Status = "confirmed"
                    _, err := db.ExecContext(ctx, "UPDATE orders SET total=$1, status=$2 WHERE id=$3", total, order.Status, order.ID)
                    if err != nil {
                        return fmt.Errorf("update order: %w", err)
                    }
                    return nil
                } else {
                    return errors.New("order total must be positive")
                }
            } else {
                return errors.New("order has no items")
            }
        } else {
            return fmt.Errorf("order status is %s, expected pending", order.Status)
        }
    } else {
        return errors.New("order is nil")
    }
}
```

Apply Go style best practices: guard clauses, early returns, and reduced nesting.

